import numpy as np
try:
    import numba as nb
except Exception:  # fallback if numba unavailable
    nb = None


def _norm2(x: np.ndarray) -> float:
    return float(np.sqrt(np.vdot(x, x).real))


if nb is not None:
    @nb.njit(cache=True)
    def _dotc(x, y):
        s = 0.0 + 0.0j
        n = x.shape[0]
        for i in range(n):
            s += np.conj(x[i]) * y[i]
        return s

    @nb.njit(cache=True)
    def _matvec(A, x):
        n = A.shape[0]
        y = np.empty(n, dtype=np.complex128)
        for i in range(n):
            s = 0.0 + 0.0j
            for j in range(n):
                s += A[i, j] * x[j]
            y[i] = s
        return y

    @nb.njit(cache=True)
    def _vec_norm(x):
        s = 0.0
        n = x.shape[0]
        for i in range(n):
            z = x[i]
            s += (z.real * z.real + z.imag * z.imag)
        return np.sqrt(s)

    @nb.njit(cache=True)
    def _fro_norm(A):
        s = 0.0
        n = A.shape[0]
        for i in range(n):
            for j in range(n):
                z = A[i, j]
                s += (z.real * z.real + z.imag * z.imag)
        return np.sqrt(s)

    @nb.njit(cache=True)
    def _normalize(x):
        nrm = _vec_norm(x)
        if nrm != 0.0:
            for i in range(x.shape[0]):
                x[i] = x[i] / nrm
        return nrm

    @nb.njit(cache=True)
    def _gram_schmidt_2(z0, z1):
        # Orthonormalize two vectors z0,z1 -> q0,q1
        q0 = z0.copy()
        n0 = _normalize(q0)
        if n0 == 0.0:
            # fallback to e0
            q0 = np.zeros(q0.shape[0], dtype=np.complex128)
            q0[0] = 1.0 + 0.0j
        # make z1 orthogonal to q0
        alpha = _dotc(q0, z1)
        q1 = z1.copy()
        for i in range(q1.shape[0]):
            q1[i] = q1[i] - alpha * q0[i]
        n1 = _normalize(q1)
        if n1 == 0.0:
            # fallback to e1 or e0 if n==1
            q1 = np.zeros(q1.shape[0], dtype=np.complex128)
            if q1.shape[0] > 1:
                q1[1] = 1.0 + 0.0j
            else:
                q1[0] = 1.0 + 0.0j
        return q0, q1

    @nb.njit(cache=True)
    def _eig2(H):
        # H is 2x2 complex matrix given as a00,a01,a10,a11
        a00, a01, a10, a11 = H[0, 0], H[0, 1], H[1, 0], H[1, 1]
        tr = a00 + a11
        det = a00 * a11 - a01 * a10
        disc = tr * tr - 4.0 * det
        s = np.sqrt(disc)
        lam1 = 0.5 * (tr + s)
        lam2 = 0.5 * (tr - s)
        # choose dominant
        if (lam1.real * lam1.real + lam1.imag * lam1.imag) >= (lam2.real * lam2.real + lam2.imag * lam2.imag):
            lam = lam1
        else:
            lam = lam2
        # eigenvector y solving (H - lam I) y = 0
        m00 = a00 - lam
        m11 = a11 - lam
        # Try y = [a01, lam - a00] or y = [lam - a11, a10]
        if (a01.real * a01.real + a01.imag * a01.imag) > (a10.real * a10.real + a10.imag * a10.imag):
            y0 = a01
            y1 = -m00
        else:
            y0 = -m11
            y1 = a10
        # normalize
        nrm = np.sqrt((y0.real * y0.real + y0.imag * y0.imag) + (y1.real * y1.real + y1.imag * y1.imag))
        if nrm != 0.0:
            y0 = y0 / nrm
            y1 = y1 / nrm
        else:
            y0 = 1.0 + 0.0j
            y1 = 0.0 + 0.0j
        return lam, y0, y1

    @nb.njit(cache=True)
    def _dominant_block_eig(A):
        n = A.shape[0]
        # Initial block Q: deterministic complex to capture complex modes
        q0 = np.zeros(n, dtype=np.complex128)
        q1 = np.zeros(n, dtype=np.complex128)
        q0[0] = 1.0 + 0.0j
        if n > 1:
            q0[1] = 0.0 + 1.0j
            q1[1] = 1.0 + 0.0j
        q1[0] = 0.0 + 1.0j
        # Orthonormalize initial block
        q0, q1 = _gram_schmidt_2(q0, q1)
        # Norm of A
        Anorm = _fro_norm(A)
        if Anorm == 0.0:
            return 0.0 + 0.0j, q0
        lam = 0.0 + 0.0j
        v = q0.copy()
        for _ in range(50):
            # Z = A @ Q
            z0 = _matvec(A, q0)
            z1 = _matvec(A, q1)
            # Orthonormalize Z -> Q
            q0, q1 = _gram_schmidt_2(z0, z1)
            # Rayleigh quotient on current subspace
            Az0 = _matvec(A, q0)
            Az1 = _matvec(A, q1)
            H = np.empty((2, 2), dtype=np.complex128)
            H[0, 0] = _dotc(q0, Az0)
            H[0, 1] = _dotc(q0, Az1)
            H[1, 0] = _dotc(q1, Az0)
            H[1, 1] = _dotc(q1, Az1)
            lam, y0, y1 = _eig2(H)
            # Ritz vector v = Q y
            v = q0 * y0 + q1 * y1
            # normalize v
            _normalize(v)
            # residual
            r = _matvec(A, v)
            for i in range(n):
                r[i] = r[i] - lam * v[i]
            res = _vec_norm(r)
            denom = Anorm + np.sqrt(lam.real * lam.real + lam.imag * lam.imag)
            if res / denom <= 1e-10:
                return lam, v
        return lam, v


def find_dominant_eigenvalue_and_eigenvector(A: np.ndarray):
    """
    Given a real square matrix A (float64), return the dominant eigenvalue and eigenvector.
    The eigenpair may be complex. The result satisfies np.allclose(A @ v, lam * v).
    """
    if A.ndim != 2 or A.shape[0] != A.shape[1]:
        raise ValueError("A must be a square 2D array")
    n = A.shape[0]
    if n == 0:
        raise ValueError("A must be non-empty")
    Ac = A.astype(np.complex128, copy=False)
    if n == 1:
        return complex(Ac[0, 0]), np.array([1.0 + 0.0j], dtype=np.complex128)
    if nb is not None:
        lam, v = _dominant_block_eig(Ac)
        return lam, v
    # Fallback: use numpy eig (may be slower)
    eigenvalues, eigenvectors = np.linalg.eig(Ac)
    idx = int(np.argmax(np.abs(eigenvalues)))
    return complex(eigenvalues[idx]), eigenvectors[:, idx]
