def _norm2(x: np.ndarray) -> float:
    return float(np.sqrt(np.vdot(x, x).real))


if nb is not None:
    @nb.njit(cache=True)
    def _dotc(x, y):
        s = 0.0 + 0.0j
        n = x.shape[0]
        for i in range(n):
            s += np.conj(x[i]) * y[i]
        return s

    @nb.njit(cache=True)
    def _matvec(A, x):
        n = A.shape[0]
        y = np.empty(n, dtype=np.complex128)
        for i in range(n):
            s = 0.0 + 0.0j
            for j in range(n):
                s += A[i, j] * x[j]
            y[i] = s
        return y

    @nb.njit(cache=True)
    def _vec_norm(x):
        s = 0.0
        n = x.shape[0]
        for i in range(n):
            z = x[i]
            s += (z.real * z.real + z.imag * z.imag)
        return np.sqrt(s)

    @nb.njit(cache=True)
    def _fro_norm(A):
        s = 0.0
        n = A.shape[0]
        for i in range(n):
            for j in range(n):
                z = A[i, j]
                s += (z.real * z.real + z.imag * z.imag)
        return np.sqrt(s)

    @nb.njit(cache=True)
    def _power8(A):
        n = A.shape[0]
        v = np.zeros(n, dtype=np.complex128)
        v[0] = 1.0 + 0.0j
        if n > 1:
            v[1] = 0.0 + 1.0j
        # normalize
        nv = _vec_norm(v)
        if nv != 0.0:
            for i in range(n):
                v[i] = v[i] / nv
        lam = 0.0 + 0.0j
        # 8 iterations
        for _ in range(8):
            w = _matvec(A, v)
            denom = _dotc(v, v)
            if denom == 0.0 + 0.0j:
                denom = 1.0 + 0.0j
            lam = _dotc(v, w) / denom
            # normalize w -> v
            nw = _vec_norm(w)
            if nw != 0.0:
                for i in range(n):
                    v[i] = w[i] / nw
            else:
                for i in range(n):
                    v[i] = 0.0 + 0.0j
                v[0] = 1.0 + 0.0j
        return lam, v


def find_dominant_eigenvalue_and_eigenvector(A: np.ndarray):
    """
